from vex import verify, Guardrail

from agno import Agent

@verify(guards=[
    Guardrail.pii_detection(block=True),
    Guardrail.keyword_block(["IP", "DOMAIN", "HASH"], block=True)
])
def threat_analyzer(input):
    agent = Agent(name="ThreatIntel", model="gpt-4o")
    return agent.run(input)

result = threat_analyzer("Analyze malware sample with IOCs: 192.168.1.1, evil.com")

from vex import verify, Guardrail
from agno import Agent

@verify(guards=[
    Guardrail.human_review(required_for="network_action"),
    Guardrail.risk_score(min_score=0.8, block=True)
])
def incident_responder(alert):
    agent = Agent(name="IncidentResponse", tools=["firewall_api"])
    response = agent.run(f"Respond to: {alert}")
    if "block" in response:
        raise ValueError("network_action")
    return response

result = incident_responder("Suspicious login from 203.0.113.5")
